## 5. GraphQL Service (gRPC Client)

파일 위치: `graphql/src/main/kotlin/com/maum/backend/service/profile/ProfileService.kt`

```kotlin
@Service
class ProfileService {
    @GrpcClient("profile-grpc")
    private lateinit var stub: ProfileServiceGrpc.ProfileServiceBlockingStub

    fun getProfile(requesterId: String, targetId: String): GetProfileResponse {
        val request = GetProfileRequest.newBuilder()
            .setRequesterId(requesterId)
            .setTargetId(targetId)
            .build()
        return try {
            stub.getProfile(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun updateProfile(userId: String, input: UpdateProfileInput): UpdateProfileResponse {
        val builder = UpdateProfileRequest.newBuilder().setUserId(userId)

        // optional 필드는 null 체크 후 선택적으로 set
        input.nickname?.let        { builder.setNickname(it) }
        input.bio?.let             { builder.setBio(it) }
        input.profileImageKey?.let { builder.setProfileImageKey(it) }
        input.birthYear?.let       { builder.setBirthYear(it) }
        input.gender?.let          { builder.setGender(it.toProto()) }
        input.height?.let          { builder.setHeight(it) }
        input.mbti?.let            { builder.setMbti(it.name) }
        input.interests?.let       { builder.addAllInterests(it) }
        input.region?.let          { builder.setRegion(it) }
        input.job?.let             { builder.setJob(it) }
        input.voiceIntroKey?.let   { builder.setVoiceIntroKey(it) }

        return try {
            stub.updateProfile(builder.build())
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
```

