## 6. 응답 DTO 및 매핑

파일 위치: `graphql/src/main/kotlin/com/maum/backend/controller/profile/ProfileDto.kt`

```kotlin
// ─── GraphQL Input ────────────────────────────
data class UpdateProfileInput(
    val nickname:        String?,
    val bio:             String?,
    val profileImageKey: String?,
    val birthYear:       Int?,
    val gender:          Gender?,
    val height:          Int?,
    val mbti:            MBTI?,
    val interests:       List<String>?,
    val region:          String?,
    val job:             String?,
    val voiceIntroKey:   String?,
)

// ─── GraphQL Response ─────────────────────────
data class UserProfileResponse(
    val userId:          String,
    val nickname:        String,
    val bio:             String?,
    val profileImageUrl: String?,
    val birthYear:       Int?,
    val age:             Int?,
    val gender:          Gender?,
    val height:          Int?,
    val mbti:            MBTI?,
    val interests:       List<String>,
    val region:          String?,
    val job:             String?,
    val voiceIntroUrl:   String?,
    val mannerScore:     Double,
    val createdAt:       String,
    val updatedAt:       String,
)

data class UpdateProfilePayload(
    val profile: UserProfileResponse,
)

// ─── Enum ─────────────────────────────────────
enum class Gender { MALE, FEMALE, OTHER }
enum class MBTI   { ISTJ, ISFJ, INFJ, INTJ, ISTP, ISFP, INFP, INTP,
                    ESTP, ESFP, ENFP, ENTP, ESTJ, ESFJ, ENFJ, ENTJ }

// ─── Proto 변환 확장 함수 ─────────────────────
fun com.maum.backend.protobuf.profile.Profile.toResponse() = UserProfileResponse(
    userId          = userId,
    nickname        = nickname,
    bio             = bio.takeIf { it.isNotBlank() },
    profileImageUrl = profileImageUrl.takeIf { it.isNotBlank() },
    birthYear       = birthYear.takeIf { it > 0 },
    age             = age.takeIf { it > 0 },
    gender          = when (gender) {
        com.maum.backend.protobuf.profile.Gender.GENDER_MALE   -> Gender.MALE
        com.maum.backend.protobuf.profile.Gender.GENDER_FEMALE -> Gender.FEMALE
        com.maum.backend.protobuf.profile.Gender.GENDER_OTHER  -> Gender.OTHER
        else -> null
    },
    height          = height.takeIf { it > 0 },
    mbti            = mbti.takeIf { it.isNotBlank() }?.let { runCatching { MBTI.valueOf(it) }.getOrNull() },
    interests       = interestsList,
    region          = region.takeIf { it.isNotBlank() },
    job             = job.takeIf { it.isNotBlank() },
    voiceIntroUrl   = voiceIntroUrl.takeIf { it.isNotBlank() },
    mannerScore     = mannerScore,
    createdAt       = createdAt,
    updatedAt       = updatedAt,
)
```

